const crypto = require('crypto');

function sha256(input) {
  return crypto.createHash('sha256').update(input).digest('hex');
}

// Same input always produces the same hash
console.log('Hash of "hello":', sha256('hello'));
console.log('Hash of "hello":', sha256('hello'));

// Tiny change produces completely different hash (avalanche effect)
console.log('Hash of "Hello":', sha256('Hello'));
console.log('Hash of "hello!":', sha256('hello!'));

// Fixed output size regardless of input size
console.log('Hash of "a":', sha256('a'));
console.log('Hash of a long string:', sha256('a'.repeat(10000)));

const crypto = require('crypto');

// Generate a key pair (similar to blockchain wallet creation)
const { privateKey, publicKey } = crypto.generateKeyPairSync('ec', {
  namedCurve: 'secp256k1',
  publicKeyEncoding: { type: 'spki', format: 'pem' },
  privateKeyEncoding: { type: 'pkcs8', format: 'pem' },
});

// Transaction data to sign
const transaction = JSON.stringify({
  from: '0xAliceAddress',
  to: '0xBobAddress',
  amount: 1.5,
  nonce: 42,
});

// Sign the transaction with the private key
const sign = crypto.createSign('SHA256');
sign.update(transaction);
const signature = sign.sign(privateKey, 'hex');
console.log('Signature:', signature.substring(0, 40) + '...');

// Verify the signature with the public key
const verify = crypto.createVerify('SHA256');
verify.update(transaction);
const isValid = verify.verify(publicKey, signature, 'hex');
console.log('Signature valid:', isValid);

// Tamper with the transaction and verify again
const tamperedTx = JSON.stringify({
  from: '0xAliceAddress',
  to: '0xBobAddress',
  amount: 100,  // changed from 1.5 to 100
  nonce: 42,
});
const verify2 = crypto.createVerify('SHA256');
verify2.update(tamperedTx);
const isTamperedValid = verify2.verify(publicKey, signature, 'hex');
console.log('Tampered signature valid:', isTamperedValid);

const crypto = require('crypto');

function sha256(input) {
  return crypto.createHash('sha256').update(input).digest('hex');
}

function mineBlock(blockData, difficulty) {
  const target = '0'.repeat(difficulty); // Hash must start with this many zeros
  let nonce = 0;
  let hash = '';
  const startTime = Date.now();

  console.log(`Mining with difficulty ${difficulty} (target: hash starts with "${target}")...`);

  while (true) {
    const input = blockData + nonce.toString();
    hash = sha256(input);

    if (hash.startsWith(target)) {
      const elapsed = Date.now() - startTime;
      console.log(`\nBlock mined!`);
      console.log(`Nonce: ${nonce}`);
      console.log(`Hash:  ${hash}`);
      console.log(`Time:  ${elapsed}ms`);
      console.log(`Attempts: ${nonce + 1}`);
      return { nonce, hash, attempts: nonce + 1, timeMs: elapsed };
    }

    nonce++;
  }
}

// Mine with increasing difficulty
const blockData = 'Block #1: Alice sends 5 BTC to Bob | prevHash: 0000abc...';

mineBlock(blockData, 1); // Easy — find hash starting with '0'
mineBlock(blockData, 2); // Harder — find hash starting with '00'
mineBlock(blockData, 3); // Even harder — find hash starting with '000'
mineBlock(blockData, 4); // Much harder — find hash starting with '0000'

const crypto = require('crypto');

function sha256(data) {
  return crypto.createHash('sha256').update(data).digest('hex');
}

class MerkleTree {
  constructor(transactions) {
    this.leaves = transactions.map(tx => sha256(tx));
    this.layers = [this.leaves];
    this.root = this.buildTree();
  }

  buildTree() {
    let currentLayer = this.leaves;

    while (currentLayer.length > 1) {
      const nextLayer = [];

      // If odd number of nodes, duplicate the last one
      if (currentLayer.length % 2 !== 0) {
        currentLayer.push(currentLayer[currentLayer.length - 1]);
      }

      for (let i = 0; i < currentLayer.length; i += 2) {
        const combinedHash = sha256(currentLayer[i] + currentLayer[i + 1]);
        nextLayer.push(combinedHash);
      }

      this.layers.push(nextLayer);
      currentLayer = nextLayer;
    }

    return currentLayer[0];
  }

  getProof(index) {
    const proof = [];
    let currentIndex = index;

    for (let i = 0; i < this.layers.length - 1; i++) {
      const layer = this.layers[i];
      const isRightNode = currentIndex % 2 === 1;
      const siblingIndex = isRightNode ? currentIndex - 1 : currentIndex + 1;

      if (siblingIndex < layer.length) {
        proof.push({
          hash: layer[siblingIndex],
          position: isRightNode ? 'left' : 'right',
        });
      }

      currentIndex = Math.floor(currentIndex / 2);
    }

    return proof;
  }

  static verify(transactionHash, proof, root) {
    let computedHash = transactionHash;

    for (const step of proof) {
      if (step.position === 'left') {
        computedHash = sha256(step.hash + computedHash);
      } else {
        computedHash = sha256(computedHash + step.hash);
      }
    }

    return computedHash === root;
  }
}

// Example usage
const transactions = [
  'Alice -> Bob: 5 BTC',
  'Bob -> Charlie: 2 BTC',
  'Charlie -> Dave: 1 BTC',
  'Eve -> Frank: 3 BTC',
];

const tree = new MerkleTree(transactions);
console.log('Merkle Root:', tree.root);
console.log('Number of layers:', tree.layers.length);

// Generate and verify a proof for the second transaction
const txIndex = 1;
const txHash = sha256(transactions[txIndex]);
const proof = tree.getProof(txIndex);
console.log('\nProof for transaction:', transactions[txIndex]);
console.log('Proof steps:', proof.length);

const isValid = MerkleTree.verify(txHash, proof, tree.root);
console.log('Proof valid:', isValid);
